import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as n,e as s,b as a}from"./app-6018dc01.js";const r={},h=s('<h1 id="深度学习" tabindex="-1"><a class="header-anchor" href="#深度学习" aria-hidden="true">#</a> 深度学习</h1><h2 id="人工智能" tabindex="-1"><a class="header-anchor" href="#人工智能" aria-hidden="true">#</a> 人工智能</h2><p>人工智能：人工搭建的智能</p><h2 id="什么是智能" tabindex="-1"><a class="header-anchor" href="#什么是智能" aria-hidden="true">#</a> 什么是智能</h2><p>智能本质上就是针对不同情境给出针对性的输出反应。人工智能就是搭建起一个根据不同的环境信息给出针对性的输出和回应的系统。如果人无法区分是在跟人还是AI聊天那么这个AI就实现了人工智能。</p><h2 id="符号主义" tabindex="-1"><a class="header-anchor" href="#符号主义" aria-hidden="true">#</a> 符号主义</h2><p>从数学的形式化推理体系中得到灵感，主张智能可以用符号的逻辑推理来模拟。这就是符号主义Symbolism。举个例子如果A表示阴天，B表示湿度大于70%，T表示将要下雨。如果A和B都是真的则T是真的。</p>',7),l=a("p",{class:"katex-block"},[a("span",{class:"katex-display"},[a("span",{class:"katex"},[a("span",{class:"katex-mathml"},[a("math",{xmlns:"http://www.w3.org/1998/Math/MathML",display:"block"},[a("semantics",null,[a("mrow",null,[a("mi",null,"A"),a("mo",null,"∧"),a("mi",null,"B"),a("mo",null,"⇒"),a("mi",null,"T")]),a("annotation",{encoding:"application/x-tex"}," A∧B⇒T ")])])]),a("span",{class:"katex-html","aria-hidden":"true"},[a("span",{class:"base"},[a("span",{class:"strut",style:{height:"0.6833em"}}),a("span",{class:"mord mathnormal"},"A"),a("span",{class:"mspace",style:{"margin-right":"0.2222em"}}),a("span",{class:"mbin"},"∧"),a("span",{class:"mspace",style:{"margin-right":"0.2222em"}})]),a("span",{class:"base"},[a("span",{class:"strut",style:{height:"0.6833em"}}),a("span",{class:"mord mathnormal",style:{"margin-right":"0.05017em"}},"B"),a("span",{class:"mspace",style:{"margin-right":"0.2778em"}}),a("span",{class:"mrel"},"⇒"),a("span",{class:"mspace",style:{"margin-right":"0.2778em"}})]),a("span",{class:"base"},[a("span",{class:"strut",style:{height:"0.6833em"}}),a("span",{class:"mord mathnormal",style:{"margin-right":"0.13889em"}},"T")])])])])],-1),i=s('<p>这套思路最成功的典范就是曾经的专家系统，他咨询人类的医学专家，什么样的病可能会有什么样的症状，把这些规则全部记录下来，只要利用这些规则，就可以根据已有的信息给出预测，实现一个智能的黑箱。这套系统一度在疾病诊断和金融质询领域获得了很大的成功。但随着时间的推移，它也暴露出致命的缺陷。首先，现实世界没有那么清晰的规则。其次，这套系统完全是在复制人类经验，所以他的能力上限就是专家的水平，无法做到比人更好。并且从设计完成这套系统开始，他就永远是静止不变的水平。其很难像人一样随着经验和时间的增长，水平不断继续提升。</p><h2 id="联结主义" tabindex="-1"><a class="header-anchor" href="#联结主义" aria-hidden="true">#</a> 联结主义</h2><p>大自然已经给出了实现智能的标准答案，那就是人类精妙的大脑。只需要通过仿生的方式，模拟单个神经元的复杂功能以及神经元之间复杂的连接即可。</p><h2 id="机器学习" tabindex="-1"><a class="header-anchor" href="#机器学习" aria-hidden="true">#</a> 机器学习</h2><p>通过给机器以奖励或者惩罚的方式，让机器自主调整不断学习从而学会解决某一种任务的智能。它不需要任何专家的专业知识来人为搭建黑箱内部的结构。它只需要两样东西，一个强大且有学习能力的黑箱以及足够多的数据。那么怎么创造这种神奇黑箱呢？怎么奖励一个机器呢？机器怎么建立条件反射呢？</p><h3 id="搭建学习黑箱" tabindex="-1"><a class="header-anchor" href="#搭建学习黑箱" aria-hidden="true">#</a> 搭建学习黑箱</h3><p>神经网络</p><blockquote><p>此时此刻恰如彼时彼刻 ----人类畅想</p></blockquote><h3 id="奖励机器" tabindex="-1"><a class="header-anchor" href="#奖励机器" aria-hidden="true">#</a> 奖励机器</h3><p>需要一种定量的方式来度量一组系数所对应的多项式到底拟合的好不好，而这就是损失函数。就是在衡量一个模型预测的和真实结果之间的编差程度。梯度说白了就是在某个给定位置函数值变化最快的方向。每次向着局部损失函数下降最快的方向前进就是梯度下降。对于一个非常复杂的神经网络，怎么计算这个梯度呢？答案就是反向传播。</p>',10),c=[h,l,i];function d(m,o){return t(),n("div",null,c)}const _=e(r,[["render",d],["__file","深度学习.html.vue"]]);export{_ as default};
